#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool isMatch(const char *s, const char *p) {
        int sLen = strlen(s);
        int pLen = strlen(p);
        vector<vector<bool>> dp(sLen + 1, vector<bool>(pLen + 1, false));
        dp[sLen][pLen] = true;
        for (int i = sLen; i >= 0; i--) {
            for (int j = pLen - 1; j >= 0; j--) {
                bool match = i < sLen && (p[j] == s[i] || p[j] == '?');
                if (p[j] == '*') {
                    dp[i][j] = dp[i][j + 1] || (i < sLen && dp[i + 1][j]);
                } else {
                    dp[i][j] = match && dp[i + 1][j + 1];
                }
            }
        }
        return dp[0][0];
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    string s, p;
    getline(cin, s);
    getline(cin, p);
    Solution sol;
    cout << (sol.isMatch(s.c_str(), p.c_str()) ? "true" : "false") << "\n";
    return 0;
}
